/**
 * @ch 歸還所有Scatter預中獎動畫節點
 */
ReturnAllScatterPreWinNodes() {
    for (const [col, scatterPreWinNode] of this.m_scatterPreWinNodes) {
        if (scatterPreWinNode) {
            PrefabPoolManager.GetInstance().ReturnNode(
                SCATTER_PRE_WIN_NODE_KEY,
                scatterPreWinNode
            );
        }
    }
    this.m_scatterPreWinNodes.clear();
}

/**
 * @ch 顯示 NearWin 輪帶特效（pirate2 風格）
 * @param col 要顯示光效的列索引
 */
ShowNearWin(col: number) {
    // 先關掉所有舊的，確保只有一條亮
    for (let i = 0; i < this.m_nearWinEffects.length; i++) {
        if (i !== col && this.m_nearWinEffects[i] && this.m_nearWinEffects[i].node.active) {
            this.m_nearWinEffects[i].FadeOut();
        }
    }
    if (col >= 0 && col < this.m_nearWinEffects.length && this.m_nearWinEffects[col]) {
        this.m_nearWinEffects[col].FadeIn();
    }
    // NearWin 壓暗：除了 NearWin 列以外全壓
    for (let c = 0; c < Game_Define.COL; ++c) {
        for (let row = 0; row < Game_Define.ROW; ++row) {
            const pos = c * Game_Define.ROW + row;
            eventManager.Dispatch(REEL_UI_MANAGER_EVENT.SET_SYMBOL_BLACK_MASK_SHOW, pos, c !== col, true);
        }
    }
}

/**
 * @ch 停止所有 NearWin 輪帶特效
 */
StopNearWin() {
    for (let col = 0; col < this.m_nearWinEffects.length; col++) {
        if (this.m_nearWinEffects[col] && this.m_nearWinEffects[col].node.active) {
            this.m_nearWinEffects[col].FadeOut();
        }
    }
    // 解暗全部
    eventManager.Dispatch(REEL_UI_MANAGER_EVENT.SET_ALL_SYMBOL_BLACK_MASK_SHOW, false, false);
}

/**
 * @ch 停止指定列的 NearWin 光效
 */
StopNearWinAt(col: number) {
    if (col >= 0 && col < this.m_nearWinEffects.length && this.m_nearWinEffects[col] && this.m_nearWinEffects[col].node.active) {
        this.m_nearWinEffects[col].FadeOut();
    }
}

/**
 * @ch NearWin 光效數量
 */
get NearWinEffectsCount(): number {
    return this.m_nearWinEffects.length;
}

/**
 * @ch 播放Scatter中獎動畫
 * @param positions 位置
 */
async PlayScatterBingoAnimation(positions: number[]) : Promise<void> {
    if (positions.length === 0) {
        return;
    }

    const symbol = Game_Define.Symbol.GoldScatter;
    let promises: Promise<void>[] = [];
    for (const position of positions) {
        const {col, row} = Common.GetColRowFromPosition(position);

        const symbolSpineNode = this.CreateEffectNode_NodePool(col, row, Game_Define.LAYERS.PRIATE, symbol);
        const symbolSpine = symbolSpineNode.getComponent(SymbolSpine);
        promises.push(symbolSpine.PlayAnim(false, true));
    }

    // 讓音效播放完
    await Define.Wait(this, WAIT_AFTER_SCATTER_BINGO_SFX_SEC);
}

/**
 * @ch 停止Scatter中獎動畫
 * @param positions 位置
 */
StopScatterBingoAnimation(positions: number[]) : void {
    if (positions.length === 0) {
        return;
    }

    for (const position of positions) {
        const {col, row} = Common.GetColRowFromPosition(position);
        this.CleanSymbolAnim(col, row, Game_Define.LAYERS.PRIATE);
    }
}
