// =============== 表演 ===============
//#region 表演
/**@ch 播放聽牌音效
 */
private PlayNearWinSound() {
    if (this.m_nearWinSoundId !== -1) {
        AudioManager.Stop(this.m_nearWinSoundId);
    }
    this.m_nearWinSoundId = AudioManager.Play(AudioManager.AudioClips.NearWin);
}

/**@ch 停止聽牌音效
 */
private StopNearWinSound() {
    if (this.m_nearWinSoundId !== -1) {
        AudioManager.Stop(this.m_nearWinSoundId);
        this.m_nearWinSoundId = -1;
    }
}

/**@ch 播放整列的Scatter動畫
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @param isLoop 是否循環播放
 */
private async PlayColumnScattersAnimation(col: number, isLoop: boolean = true): Promise<void> {
    if ( col < 0 || col >= Game_Define.COL )
    {
        error( `PlayColumnScattersAnimation: 無效的列索引 ${col}` );
        return;
    }


    const featurePosQueue = this.m_featurePosQueue.find(item => item.type === FeaturePosQueueType.Scatter && item.positions.some(position => position.col === col));
    if (!featurePosQueue) {

        return;
    }

    let promises: Promise<void>[] = [];
    const positionsForCol = featurePosQueue.positions.filter(position => position.col === col);
    for (const position of positionsForCol) {
        promises.push(this.PlayScatterAnimation(position.col, position.row, isLoop));
    }
    await Promise.all(promises);
}

/**@ch NearWin 時播放整列 Scatter Enter 動畫（loop）
 * @param col 列索引
 */
private async PlayColumnScattersEnterAnimation(col: number): Promise<void> {
    const featurePosQueue = this.m_featurePosQueue.find(item => item.type === FeaturePosQueueType.Scatter && item.positions.some(position => position.col === col));
    if (!featurePosQueue) return;

    const positionsForCol = featurePosQueue.positions.filter(position => position.col === col);
    for (const position of positionsForCol) {
        this.m_gameView.EffectPlate.PlayScatterEnterAnimation(position.col, position.row, true);
    }
}

/**@ch 播放單一符號的 Scatter Stop 動畫（只播 Stop，不接 Enter）
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @param row 行索引 (0 ~ Game_Define.ROW-1)
 * @param isLoop 是否循環播放（未使用，保留相容）
 */
private async PlayScatterAnimation(col: number, row: number, isLoop: boolean) : Promise<void> {
    // 隱藏符號
    this.SetSymbolShow(col, row, false);

    // 記錄隱藏的位置
    this.m_hiddenScatterPositions.push({col, row});

    const scatterCount = Math.min(this.m_hiddenScatterPositions.length, Game_Define.SCATTER_MAX_COUNT);
    AudioManager.Play(`Scatter0${scatterCount}`);

    // 決定 Scatter Stop 動畫等級
    let scatterStopLevel = 0;
    if (this.m_gameView.IsFreeGame) {
        scatterStopLevel = this.m_gameView.HasScatterBoost ? 2 : 1;
    }

    // 播 Stop 動畫
    await this.m_gameView.EffectPlate.PlayScatterStopAnimation(col, row, scatterStopLevel);
}

/**@ch 停止所有 Column 的 Scatter 動畫
 */
private StopAllColumnScattersAnimation() {
    this.m_gameView.EffectPlate.ReturnAllScatterEnterAnimationNodes();

    // 恢復所有之前隱藏的 Scatter 符號
    for (const pos of this.m_hiddenScatterPositions) {
        this.SetSymbolShow(pos.col, pos.row, true);
    }
    // 清空記錄列表
    this.m_hiddenScatterPositions = [];
}

