/**
 * @ch 歸還消除表演節點
 * @param positions 位置
 * @param isRecoverSymbolShow 是否恢復Symbol顯示
 */
ReturnEliminateEffectNodes(positions: number[], isRecoverSymbolShow: boolean) : void {
    if (positions.length === 0) {
        return;
    }

    for (const symbolPosition of positions) {
        const { col, row } = Common.GetColRowFromPosition(symbolPosition);
        if (isRecoverSymbolShow) {
            this.SetSymbolShow(col, row, true);
        }
        this.CleanSymbolAnim(col, row, Game_Define.LAYERS.PRIATE);
    }
}
