async PlayScatterStopAnimation(col: number, row: number, level: number = 0, onSpineReady?: (spine: BaseSpine) => void) : Promise<void> {
    const position = Common.GetPositionFromColRow(col, row);
    let scatterSpine: BaseSpine;

    if (this.m_scatterAnimationSpines.has(position)) {
        scatterSpine = this.m_scatterAnimationSpines.get(position);
        if (scatterSpine && (scatterSpine.node['_reparented'] || level > 0)) {
            // level > 0 時強制重建（Enter 動畫用的是 level 0 prefab）

            scatterSpine.Stop();
            scatterSpine.node.removeFromParent();
            const oldKey = scatterSpine.node['_prefabKey'] || SCATTER_ANIMATION_PREFAB_KEY0;
            PrefabPoolManager.GetInstance().ReturnNode(oldKey, scatterSpine.node);
            this.m_scatterAnimationSpines.delete(position);
            scatterSpine = null;
        } else if (scatterSpine) {
            scatterSpine.Stop();
        }
    }
    if (!scatterSpine) {
        let prefabKey = SCATTER_ANIMATION_PREFAB_KEY0;
        if (level === 1) prefabKey = SCATTER_ANIMATION_PREFAB_KEY1;
        else if (level >= 2) prefabKey = SCATTER_ANIMATION_PREFAB_KEY2;

        const scatterNode = PrefabPoolManager.GetInstance().GetNode(prefabKey);
        if (!scatterNode) { warn(`[PlayScatterStopAnimation] GetNode returned null!`); return; }

        if (!scatterNode) return;
        scatterSpine = scatterNode.getComponent(BaseSpine);
        if (!scatterSpine) {
            PrefabPoolManager.GetInstance().ReturnNode(prefabKey, scatterNode);
            return;
        }
        scatterNode['_prefabKey'] = prefabKey;
        scatterNode.setParent(this.m_effectNodes[Game_Define.LAYERS.SYMBOL]);
        this.m_scatterAnimationSpines.set(position, scatterSpine);

        // 新建節點需要等幾幀讓 Spine 初始化渲染
        scatterSpine.node.setWorldPosition(this.GetSymbolNodeWorldPos(col, row));
        scatterSpine.node.active = true;
        scatterSpine.node.children.forEach(child => { child.active = true; });
        if (scatterSpine.Spine) {
            scatterSpine.Spine.enabled = true;
            scatterSpine.Spine.updateAnimation(0);
        }
    }

    scatterSpine.node.setWorldPosition(this.GetSymbolNodeWorldPos(col, row));
    scatterSpine.node.active = true;

    if (onSpineReady) {
        onSpineReady(scatterSpine);
    }

    // 直接用 sp.Skeleton 播 Stop 動畫
    const spine = scatterSpine.node.getComponentInChildren(sp.Skeleton);
    if (!spine) return;
    spine.enabled = true;
    spine.setAnimation(0, SCATTER_STOP_ANIMATION_SPINE_KEY, false);
    spine.updateAnimation(0);
    await new Promise<void>(resolve => {
        spine.setCompleteListener(() => {
            spine.setCompleteListener(null);
            resolve();
        });
    });


}

async PlayScatterIdleAnimation(col: number, row: number, isLoop: boolean, level: number = 0, onSpineReady?: (spine: BaseSpine) => void) : Promise<void> 
{
    const position = Common.GetPositionFromColRow(col, row);
    let scatterSpine: BaseSpine;

    // 檢查同位置是否已有 Spine
    if (this.m_scatterAnimationSpines.has(position)) {
        scatterSpine = this.m_scatterAnimationSpines.get(position);
        if (scatterSpine && scatterSpine.node['_reparented']) {
            this.m_scatterAnimationSpines.delete(position);
            scatterSpine = null;
        } else if (scatterSpine) {
            // level 不匹配時重建
            const curKey = scatterSpine.node['_prefabKey'] || SCATTER_ANIMATION_PREFAB_KEY0;
            let wantKey = SCATTER_ANIMATION_PREFAB_KEY0;
            if (level === 1) wantKey = SCATTER_ANIMATION_PREFAB_KEY1;
            else if (level >= 2) wantKey = SCATTER_ANIMATION_PREFAB_KEY2;
            if (curKey !== wantKey) {
                scatterSpine.Stop();
                scatterSpine.node.removeFromParent();
                PrefabPoolManager.GetInstance().ReturnNode(curKey, scatterSpine.node);
                this.m_scatterAnimationSpines.delete(position);
                scatterSpine = null;
            } else {
                scatterSpine.Stop();
            }
        }
    }
    if (!scatterSpine) {
        // 同位置無：新建 Spine
        let prefabKey = SCATTER_ANIMATION_PREFAB_KEY0;
        if (level === 1) prefabKey = SCATTER_ANIMATION_PREFAB_KEY1;
        else if (level >= 2) prefabKey = SCATTER_ANIMATION_PREFAB_KEY2;

        const scatterEnterAnimationNode = PrefabPoolManager.GetInstance().GetNode(prefabKey);
        if (!scatterEnterAnimationNode) {
            return;
        }
        scatterEnterAnimationNode['_prefabKey'] = prefabKey;

        // 取得 Spine 組件
        scatterSpine = scatterEnterAnimationNode.getComponent(BaseSpine);
        if (!scatterSpine) {
            PrefabPoolManager.GetInstance().ReturnNode(prefabKey, scatterEnterAnimationNode);
            return;
        }

        // 設定父節點
        scatterEnterAnimationNode.setParent(this.m_effectNodes[Game_Define.LAYERS.SYMBOL]);

        // 存儲 Spine 到 Map
        this.m_scatterAnimationSpines.set(position, scatterSpine);
    }

    // 設定位置（無論新建或復用都需要設定）
    scatterSpine.node.setWorldPosition(this.GetSymbolNodeWorldPos(col, row));

    // 顯示節點
    scatterSpine.node.active = true;

    // Spine初始化完成，呼叫回調
    if (onSpineReady) {
        onSpineReady(scatterSpine);
    }

    // 播放動畫
    await scatterSpine.PlayAnimation(
        SCATTER_IDLE_ANIMATION_SPINE_KEY,
        scatterSpine.Spine,
        isLoop
    );


}

