        AudioManager.Play(AudioManager.AudioClips.Scatter4);
    } else if (count === 3) {
        AudioManager.Play(AudioManager.AudioClips.Scatter3);
    } else if (count === 2) {
        AudioManager.Play(AudioManager.AudioClips.Scatter2);
    } else if (count === 1) {
        AudioManager.Play(AudioManager.AudioClips.Scatter1);
    } else {
        AudioManager.Play(AudioManager.AudioClips.Reel_Stop);
    }
}

/**
 * @ch 根據指定 count 播放 Scatter 停輪音效（掉落模式用）
 */
PlayReelSoundByCount(count: number) {
    if (count >= 5) {
        AudioManager.Play(AudioManager.AudioClips.Scatter5);
    } else if (count === 4) {
        AudioManager.Play(AudioManager.AudioClips.Scatter4);
    } else if (count === 3) {
        AudioManager.Play(AudioManager.AudioClips.Scatter3);
    } else if (count === 2) {
        AudioManager.Play(AudioManager.AudioClips.Scatter2);
    } else if (count >= 1) {
        AudioManager.Play(AudioManager.AudioClips.Scatter1);
    }
}

/**
 * @ch 更新停輪相關時間
 * @en Update stopTime, reelStopTime, reelPreTime and ClickStopBtn
 */
ClickStopBtn()
{
    if ( this.StopTime === 0 )
    {
        return;
    }

    this.m_isClickStopBtn = true;

    for ( let i = 0; i < Game_Define.COL; ++i )
    {
        let isNearWin = false;
        let spinTime = this.CalSpinTime( i, isNearWin );
        let timesOfSpin = Math.ceil( this.m_time / spinTime ); // NOTE: 不加一的話有可能會偷換圖
        timesOfSpin = timesOfSpin > 0 ? timesOfSpin : 1;
        let reelPreTime = ( timesOfSpin - 1 ) * spinTime; // 差一圈就要停時的時間
        let reelStopTime = this.ToolsStrip( reelPreTime + spinTime );
        if ( this.m_reelStopTime[ i ] > reelStopTime )
        {
            this.m_reelStopTime[ i ] = reelStopTime;
            this.m_reelPreTime[ i ] = reelPreTime;
        }
    }

    // 計算快停時間，需要加上 riseTime 和緩衝時間
    const riseTime = this.m_riseTime * Game_Define.COL;
    let stopTime = this.CalClickStopButtonFinishTime( this.m_time );

    // 加上必要的緩衝時間，確保回彈階段能完成
    stopTime = this.ToolsStrip( stopTime + riseTime + this.m_spinBufferTime01 + this.m_spinBufferTime02 );

    if ( stopTime < this.m_stopTime )
    {
        this.StopTime = this.ToolsStrip( stopTime );
    }
}

