import { _decorator, log } from "cc";
import { stateManager, BaseState, SlotBottomBarState, newBottombarManager, eventManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define, { FeaturePosQueueType } from "../Game_Define";
import { Common } from "../Common/Common";
import { FREE_GAME_DECLARE_MANAGER_EVENT } from "../FreeGame/FreeGameDeclareManager";
import { FREE_GAME_UI_MANAGER_EVENT } from "../FreeGame/FreeGameUIManager";
import { REEL_UI_MANAGER_EVENT, UIType } from "../Reel/ReelManager";
import { BACKGROUND_MANAGER_EVENT, BackgroundType } from "../BackgroundManager";
import { Define } from "db://astarte-framework/utilis";
import { BS_SPINE_CTRL_EVENT } from "../BSSpineCtrl";
import { BS_SPINE_TYPE } from "../BSSpineCtrl";
import { CHARACTER_ANIM_NAME } from "../BSSpineCtrl";
import { AudioManager } from "../Audio/AudioManager";

const { ccclass } = _decorator;
@ccclass( "EnterFreeState" )
export class EnterFreeState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {

        log( "OnEnter State : ENTER_FREE" );
        await Define.Wait(this.m_gameView, 0.8);

        Common.SetLockOrientation(true);

        // 暫停主遊戲背景音樂
        this.m_gameView.PauseMainGameBgm();
        AudioManager.Play(AudioManager.AudioClips.Scatter_bell);

        newBottombarManager.SetEnterFree();
        this.StopEffect();
        this.m_gameView.IsFreeGame = true;
        this.m_gameView.FreePickItems = (this.m_gameView.SpinAck.RoundQueue[ 0 ].FreePickItem as number[]) || [];

        this.m_gameView.RoundWin = this.m_gameView.SpinAck.RoundQueue[ 0 ].RoundWin;
        this.m_gameView.FreeTotalRound = this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurRoundIndex ].FeverTotalRound;
        newBottombarManager.SetBarNodeVisiable( false );
        this.m_gameView.BuyBonus?.SetBuyBtnVisible( false );
        this.m_gameView.SetExtraBetVisible( false );
        this.m_gameView.SetManualVisible( false );


        // 播放 Scatter Idle 動畫（進場動畫期間就顯示）
        this.PlayScatterIdle();

        // 播放免費遊戲進場演出（midCb 會設定 spin 狀態並 NextState）
        this.PlayFreeGameEnterAnim();
    }

    public OnProcess() 
    {

    }

    public OnLeave() 
    {
        Common.SetLockOrientation(false);
    }

    /**
     * @ch 停止效果
     */
    private StopEffect()
    {
        this.m_gameView.ClearAll();
        this.m_gameView.EffectPlate.CurAwardLines.length = 0;
    }

    /**
     * @ch 設置免費遊戲盤面
     */
    private SetFreeGamePlate()
    {
        // 顯示轉輪盤面UI
        eventManager.Dispatch( REEL_UI_MANAGER_EVENT.SHOW);

        // 切換到免費遊戲UI
        eventManager.Dispatch( REEL_UI_MANAGER_EVENT.CHANGE_UI, UIType.FreeGame );

        // 設定免費遊戲盤面
        //this.m_gameView.SlotReels.SetFreeGamePlate();

        // 顯示免費遊戲回合數字
        eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.SET_REMAINING_ROUND, 
            this.m_gameView.RoundInfo.FeverNowRound, 
            this.m_gameView.RoundInfo.FeverTotalRound);
        //eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.SET_REMAINING_ROUND, 0, 10);
        // // 重置進度節點的透明度
        // eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.RESET_PROGRESS, false);
    }

    /**
     * @ch 播放 Scatter Idle 動畫（進 FG 後等待 spin 時）
     */
    private PlayScatterIdle()
    {
        const plateQueue = this.m_gameView.RoundInfo.PlateQueue;
        if ( !plateQueue || plateQueue.length === 0 ) return;
        const lastPlate = plateQueue[ plateQueue.length - 1 ];
        if ( !lastPlate.FeaturePosQueue || lastPlate.FeaturePosQueue.length === 0 ) return;
        const scatterQueue = lastPlate.FeaturePosQueue[ FeaturePosQueueType.Scatter ];
        if ( !scatterQueue || !scatterQueue.Data ) return;

        const scatterLevel = 0; // 進場時保持 MG 的 Scatter 外觀，FG spin 時才升級
        for ( const pos of scatterQueue.Data )
        {
            const { col, row } = Common.GetColRowFromPosition( pos );
            this.m_gameView.SlotReels.SetSymbolShow( col, row, false );
            this.m_gameView.EffectPlate.PlayScatterIdleAnimation( col, row, true, scatterLevel );
        }
    }

    /**
     * @ch 播放免費遊戲進場演出
     * @returns 
     */
    private async PlayFreeGameEnterAnim() : Promise<void>
    {
        return new Promise<void>(async (resolve) => {
            let winPromises: Promise<void>[] = [];
            winPromises.push( new Promise(
                async ( resolve ) =>
                {
                    AudioManager.Play(AudioManager.AudioClips.Target_Explode_Explosion);
                    eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, 
                        CHARACTER_ANIM_NAME.Win0, false, ()=>{ resolve();});
                })
            );

            await Promise.all( winPromises );

            AudioManager.Play(AudioManager.AudioClips.FG_Into);
            eventManager.Dispatch(FREE_GAME_DECLARE_MANAGER_EVENT.PLAY_DECLARE_ANIM, this.m_gameView.RoundInfo.FeverRemainRound, () => {
                this.SetFreeGamePlate();
                // 背景切換由 FreePickRouletteState 的 WheelSpine Out BG_End event 觸發

                // 退場開始時就顯示下 bar、播 BGM、設定 spin 狀態
                this.m_gameView.PlayFreeGameBgm();
                eventManager.Dispatch(BACKGROUND_MANAGER_EVENT.CHANGE_BACKGROUND, BackgroundType.FreeGame);
                newBottombarManager.SetBarNodeVisiable( true );
                if ( newBottombarManager.IsAutoSpin ) {
                    if ( this.m_gameView.AutoplayInfos.isCheckFree ) {
                        newBottombarManager.ShowAutoPlayState( false );
                        newBottombarManager.SetSpinState( SlotBottomBarState.IDLE );
                        this.m_gameView.IsFirstRound = true;
                    } else {
                        this.m_gameView.IsFirstRound = false;
                    }
                } else {
                    newBottombarManager.SetSpinState( SlotBottomBarState.IDLE );
                    this.m_gameView.IsFirstRound = true;
                }
                stateManager.NextState( Game_Define.GameState.FREE_PICK_ROULETTE );
            }, () => {
                resolve();
            });
         });
    }
}

